-- Program: Blogilates Inspired
-- Category: Viral TikTok Programs -> viral
-- Priority: High
-- Durations: [2, 4, 8], Sessions: [4, 5]

-- Insert branded program
INSERT INTO branded_programs (
    name, description, category, difficulty_level,
    duration_weeks, sessions_per_week, split_type,
    goals, requires_gym, is_active
) VALUES (
    'Blogilates Inspired',
    'Pop pilates sculpting workout with fun music-driven Pilates moves for lean muscle',
    'viral',
    'all_levels',
    8,
    5,
    'flow',
    ARRAY['Maximize muscle hypertrophy', 'Time under tension', 'Maximize calorie burn', 'Preserve lean muscle', 'Improve flexibility']::text[],
    true,
    true
) ON CONFLICT (name) DO UPDATE SET
    description = EXCLUDED.description,
    category = EXCLUDED.category,
    difficulty_level = EXCLUDED.difficulty_level,
    duration_weeks = EXCLUDED.duration_weeks,
    sessions_per_week = EXCLUDED.sessions_per_week,
    split_type = EXCLUDED.split_type,
    goals = EXCLUDED.goals,
    requires_gym = EXCLUDED.requires_gym,
    updated_at = NOW();

-- Variant: Blogilates Inspired - 2w 4x/wk
INSERT INTO program_variants (
    base_program_id,
    intensity_level,
    duration_weeks,
    variant_name,
    program_category,
    sessions_per_week,
    session_duration_minutes,
    goals,
    workouts
) SELECT
    bp.id,
    'Medium',
    2,
    'Blogilates Inspired - 2w 4x/wk',
    'viral',
    4,
    60,
    ARRAY['Maximize muscle hypertrophy', 'Time under tension', 'Maximize calorie burn', 'Preserve lean muscle', 'Improve flexibility']::text[],
    '[]'::jsonb
FROM branded_programs bp
WHERE bp.name = 'Blogilates Inspired'
ON CONFLICT DO NOTHING;

